import{_ as e,o as t,c as o,ae as a}from"./chunks/framework.BGHOrOyn.js";const m=JSON.parse('{"title":"PixHawk","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/pixhawk/README.md","filePath":"robotics/pixhawk/README.md"}'),i={name:"robotics/pixhawk/README.md"};function n(p,r,s,c,h,l){return t(),o("div",null,[...r[0]||(r[0]=[a('<h1 id="pixhawk" tabindex="-1">PixHawk <a class="header-anchor" href="#pixhawk" aria-label="Permalink to &quot;PixHawk&quot;">​</a></h1><hr><h2 id="pixhawk-wiring-quick-start¶" tabindex="-1">Pixhawk Wiring Quick Start<a href="https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#pixhawk-wiring-quick-start" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#pixhawk-wiring-quick-start¶" aria-label="Permalink to &quot;Pixhawk Wiring Quick Start[¶](https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#pixhawk-wiring-quick-start)&quot;">​</a></h2><p>This article provides high level information about how to power Pixhawk and connect its most important peripherals.</p><p>Warning</p><p>Do not connect any servos or other devices to the PWM outputs of your receiver. The RCIN port on the Pixhawk is designed for low power devices only, and a servo or relay may draw a lot of current from the receiver. If you connect a servo directly onto your receiver while the receiver is powered from the RCIN port of your Pixhawk you may damage your Pixhawk.</p><h3 id="pixhawk-wiring-chart¶" tabindex="-1">Pixhawk Wiring Chart<a href="https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#pixhawk-wiring-chart" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#pixhawk-wiring-chart¶" aria-label="Permalink to &quot;Pixhawk Wiring Chart[¶](https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#pixhawk-wiring-chart)&quot;">​</a></h3><p><a href="https://ardupilot.org/copter/_images/pixhawk_connect_essential_peripherals.jpg" target="_blank" rel="noreferrer"><img src="https://ardupilot.org/copter/_images/pixhawk_connect_essential_peripherals.jpg" alt="../images/pixhawkconnectessentialperipherals.jpg"></a></p><p>Copter users should also see the <a href="https://ardupilot.org/copter/docs/advanced-pixhawk-quadcopter-wiring-chart.html#advanced-pixhawk-quadcopter-wiring-chart" target="_blank" rel="noreferrer">Advanced Pixhawk Quadcopter Wiring Chart</a>.</p><h3 id="power-pixhawk¶" tabindex="-1">Power Pixhawk<a href="https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#power-pixhawk" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#power-pixhawk¶" aria-label="Permalink to &quot;Power Pixhawk[¶](https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#power-pixhawk)&quot;">​</a></h3><p>Pixhawk is typically powered via its “power” port, as shown in the picture below. The power port simultaneously powers Pixhawk and reads voltage and current analog measurements produced by an optional power module. Information about powering the Pixhawk can be found in the topic <a href="https://ardupilot.org/copter/docs/common-powering-the-pixhawk.html#common-powering-the-pixhawk" target="_blank" rel="noreferrer">Powering the Pixhawk</a>.</p><p><a href="https://ardupilot.org/copter/_images/pixhawkpower-port.jpg" target="_blank" rel="noreferrer"><img src="https://ardupilot.org/copter/_images/pixhawkpower-port.jpg" alt="../images/pixhawkpower-port.jpg"></a></p><h3 id="connect-remote-control-inputs¶" tabindex="-1">Connect remote control inputs<a href="https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#connect-remote-control-inputs" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#connect-remote-control-inputs¶" aria-label="Permalink to &quot;Connect remote control inputs[¶](https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#connect-remote-control-inputs)&quot;">​</a></h3><p>Pixhawk is compatible with</p><blockquote><ol><li>PPM-Sum receivers</li><li>SBus receivers</li><li>IBUS receivers</li><li><a href="https://ardupilot.org/copter/docs/common-FPort-receivers.html#common-fport-receivers" target="_blank" rel="noreferrer">FPort Receivers</a></li><li><a href="https://ardupilot.org/copter/docs/common-spektrum-rc.html#common-spektrum-rc" target="_blank" rel="noreferrer">Spektrum DSM, DSM2, and DSM-X Satellite receivers</a></li><li><a href="https://ardupilot.org/copter/docs/common-srxl-receivers.html#common-srxl-receivers" target="_blank" rel="noreferrer">SRXL version 1 and version 2 receivers</a></li><li><a href="https://ardupilot.org/copter/docs/common-graupner-rc.html#common-graupner-rc" target="_blank" rel="noreferrer">Graupner SUM-D</a></li></ol></blockquote><p>For traditional single-wire-per-channel (PWM) receivers a PPM encoder can be used to convert the receiver outputs to PPM-SUM.</p><p>Tip</p><p>Information about compatible receivers and how they are connected can be found in <a href="https://ardupilot.org/copter/docs/common-rc-systems.html#common-rc-systems" target="_blank" rel="noreferrer">Radio Control Systems</a></p><p><a href="https://ardupilot.org/copter/_images/FRSkyTaranis.jpg" target="_blank" rel="noreferrer"><img src="https://ardupilot.org/copter/_images/FRSkyTaranis.jpg" alt="../images/FRSkyTaranis.jpg"></a></p><p>FRSky Taranis Transmitter<a href="https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#id1" target="_blank" rel="noreferrer">¶</a></p><h3 id="connect-buzzer-and-safety-switch¶" tabindex="-1">Connect buzzer and safety switch<a href="https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#connect-buzzer-and-safety-switch" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#connect-buzzer-and-safety-switch¶" aria-label="Permalink to &quot;Connect buzzer and safety switch[¶](https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#connect-buzzer-and-safety-switch)&quot;">​</a></h3><p>The buzzer and safety switch button are mandatory for Pixhawk. Connect to the BUZZER and SWITCH ports as shown.</p><p><a href="https://ardupilot.org/copter/_images/pixhawk-required_peripherals.jpg" target="_blank" rel="noreferrer"><img src="https://ardupilot.org/copter/_images/pixhawk-required_peripherals.jpg" alt="../images/pixhawk-requiredperipherals.jpg"></a></p><p>Warning</p><p>Mount the beeper at least 5cm away from the flight controller or the noise may upset the accelerometers.</p><h3 id="_3dr-gps-compass¶" tabindex="-1">3DR GPS+Compass<a href="https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#dr-gps-compass" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#_3dr-gps-compass¶" aria-label="Permalink to &quot;3DR GPS+Compass[¶](https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#dr-gps-compass)&quot;">​</a></h3><p>The <a href="https://ardupilot.org/copter/docs/common-installing-3dr-ublox-gps-compass-module.html#common-installing-3dr-ublox-gps-compass-module" target="_blank" rel="noreferrer">3DR UBlox GPS + Compass Module</a> is the recommended GPS for Pixhawk on ArduPilot. The GPS ports are connected with the six-position DF13 cable, and the MAG port is connected to the I2C port with the four-position DF13 cable.</p><p><a href="https://ardupilot.org/copter/_images/GPS_TopAndSide.jpg" target="_blank" rel="noreferrer"><img src="https://ardupilot.org/copter/_images/GPS_TopAndSide.jpg" alt="../images/GPSTopAndSide.jpg"></a></p><p>3DR UBlox GPS + Compass Module<a href="https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#id2" target="_blank" rel="noreferrer">¶</a></p><p>The topic <a href="https://ardupilot.org/copter/docs/common-installing-3dr-ublox-gps-compass-module.html#common-installing-3dr-ublox-gps-compass-module" target="_blank" rel="noreferrer">3DR UBlox GPS + Compass Module</a> shows how to connect to Pixhawk and include additional configuration and mounting information.</p><h3 id="connect-motors¶" tabindex="-1">Connect Motors<a href="https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#connect-motors" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#connect-motors¶" aria-label="Permalink to &quot;Connect Motors[¶](https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#connect-motors)&quot;">​</a></h3><p><a href="https://ardupilot.org/copter/_images/pixhawk_motor_outputs.jpg" target="_blank" rel="noreferrer"><img src="https://ardupilot.org/copter/_images/pixhawk_motor_outputs.jpg" alt="../images/pixhawkmotoroutputs.jpg"></a></p><p>For Copter see <a href="https://ardupilot.org/copter/docs/connect-escs-and-motors.html#connect-escs-and-motors" target="_blank" rel="noreferrer">Connect ESCs and Motors</a>.</p><p>In overview, for copters connect each signal wire from the PDB to the main output signal (S) pins by motor number:</p><ul><li>Pin 1 = Motor 1 - - Pin 5 = Motor 5</li><li>Pin 2 = Motor 2 - - Pin 6 = Motor 6</li><li>Pin 3 = Motor 3 - - Pin 7 = Motor 7</li><li>Pin 4 = Motor 4 - - Pin 8 = Motor 8</li></ul><h3 id="connect-other-peripherals¶" tabindex="-1">Connect other peripherals<a href="https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#connect-other-peripherals" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#connect-other-peripherals¶" aria-label="Permalink to &quot;Connect other peripherals[¶](https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#connect-other-peripherals)&quot;">​</a></h3><p>Depending on your hardware there may be any number of other peripherals attached, including sensors, cameras, grippers etc. These can be found as sub-pages of the topic <a href="https://ardupilot.org/copter/docs/common-optional-hardware.html#common-optional-hardware" target="_blank" rel="noreferrer">Optional Hardware</a>.</p><p>Information about connecting these peripherals to Pixhawk is found in the respective pages.</p><h3 id="related-information¶" tabindex="-1">Related information<a href="https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#related-information" target="_blank" rel="noreferrer">¶</a> <a class="header-anchor" href="#related-information¶" aria-label="Permalink to &quot;Related information[¶](https://ardupilot.org/copter/docs/common-pixhawk-wiring-and-quick-start.html#related-information)&quot;">​</a></h3><ul><li><a href="https://ardupilot.org/copter/docs/common-pixhawk-overview.html#common-pixhawk-overview" target="_blank" rel="noreferrer">Pixhawk Overview</a> - includes specifications, pin assignments etc.</li><li><a href="https://ardupilot.org/copter/docs/common-powering-the-pixhawk.html" target="_blank" rel="noreferrer">Powering the Pixhawk</a></li><li><a href="https://ardupilot.org/copter/docs/advanced-pixhawk-quadcopter-wiring-chart.html" target="_blank" rel="noreferrer">Advanced Pixhawk Quadcopter Wiring Chart</a></li></ul>',40)])])}const g=e(i,[["render",n]]);export{m as __pageData,g as default};
